import { Component, OnInit, isDevMode } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { ElectronService } from '../../services/electron.service';

// ✅ adapte le type si ton modèle s'appelle autrement
import { Quote } from '../../models/quote';
import { QuoteStoreService } from '../../services/quote-store.service';

type QuoteTotals = {
  baseHT: number;        // HT après remise si remise
  remise: number;
  fodec: number;         // 1%
  totalHorsTVA: number;  // HT + fodec
};

@Component({
  selector: 'app-quote-preview',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './quote-preview.component.html',
  styleUrls: ['./quote-preview.component.css']
})
export class QuotePreviewComponent implements OnInit {
  quote: Quote | null = null;

  logoAvailable = true;
  readonly isDev = isDevMode();

  // DEVIS totals (no TVA, no TTC)
  totals: QuoteTotals = { baseHT: 0, remise: 0, fodec: 0, totalHorsTVA: 0 };
  totalText = '';

  private readonly FODEC_RATE = 0.01;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private store: QuoteStoreService,
    public electron: ElectronService
  ) {}

  async ngOnInit(): Promise<void> {
    await this.store.load();

    const id =
      this.route.snapshot.paramMap.get('id') ??
      this.route.snapshot.paramMap.get('quoteId') ??
      this.route.snapshot.queryParamMap.get('id') ??
      '';

    if (!id) {
      this.quote = null;
      return;
    }

    const q = await this.store.getById(id);
    this.quote = q;

    if (!q) return;

    this.computeTotals(q);
  }

  lineHT(line: any): number {
    const qte = Number(line?.quantite ?? 0);
    const pu = Number(line?.prixUnitaire ?? 0);
    return this.round3(qte * pu);
  }

  print(): void {
    window.print();
  }

  async exportPdf(): Promise<void> {
    if (!this.quote) return;
    if (!this.electron.isElectron) return;

    try {
      const anyElectron: any = this.electron as any;

      if (typeof anyElectron.exportPdf === 'function') {
        await anyElectron.exportPdf();
        return;
      }

      if (anyElectron.ipcRenderer?.invoke) {
        await anyElectron.ipcRenderer.invoke('export-pdf');
        return;
      }

      alert('Export PDF non configuré dans ElectronService.');
    } catch (e) {
      console.error(e);
      alert('Erreur export PDF. Voir console.');
    }
  }

  private computeTotals(q: Quote): void {
    const totalHT = this.round3((q.lignes ?? []).reduce((sum: number, l: any) => sum + this.lineHT(l), 0));

    // Remise
    let remise = 0;
    const type = (q as any).remiseType;
    const value = Number((q as any).remiseValue ?? 0);

    if (value > 0) {
      if (type === 'pourcentage') remise = this.round3(totalHT * (value / 100));
      else remise = this.round3(value);
    }

    const baseHT = this.round3(Math.max(0, totalHT - remise));
    const fodec = this.round3(baseHT * this.FODEC_RATE);
    const totalHorsTVA = this.round3(baseHT + fodec);

    this.totals = { baseHT, remise, fodec, totalHorsTVA };
    this.totalText = this.numberToFrenchWords(totalHorsTVA);
  }

  private round3(n: number): number {
    return Math.round((n + Number.EPSILON) * 1000) / 1000;
  }

  private numberToFrenchWords(value: number): string {
    const rounded = Math.round(value * 1000) / 1000;
    const dinars = Math.floor(rounded);
    const milli = Math.round((rounded - dinars) * 1000);

    const dinarsTxt = this.toWordsFr(dinars);
    const milliTxt = this.toWordsFr(milli);

    return `${dinarsTxt} dinars ${milliTxt} millimes`.toUpperCase();
  }

  private toWordsFr(n: number): string {
    if (!Number.isFinite(n)) return 'zéro';
    if (n === 0) return 'zéro';

    const units = [
      'zéro','un','deux','trois','quatre','cinq','six','sept','huit','neuf',
      'dix','onze','douze','treize','quatorze','quinze','seize','dix-sept','dix-huit','dix-neuf'
    ];
    const tens = ['','', 'vingt','trente','quarante','cinquante','soixante','soixante','quatre-vingt','quatre-vingt'];

    const under100 = (x: number): string => {
      if (x < 20) return units[x];
      const t = Math.floor(x / 10);
      const u = x % 10;

      if (t === 7 || t === 9) {
        const base = t === 7 ? 60 : 80;
        return `${under100(base)}-${under100(x - base)}`;
      }

      if (t === 8 && u === 0) return 'quatre-vingts';
      if (u === 0) return tens[t];
      if (u === 1 && t !== 8) return `${tens[t]} et un`;
      return `${tens[t]}-${units[u]}`;
    };

    const under1000 = (x: number): string => {
      if (x < 100) return under100(x);
      const h = Math.floor(x / 100);
      const r = x % 100;
      const hTxt = h === 1 ? 'cent' : `${units[h]} cent${r === 0 ? 's' : ''}`;
      return r === 0 ? hTxt : `${hTxt} ${under100(r)}`;
    };

    if (n < 1000) return under1000(n);

    if (n < 1000000) {
      const k = Math.floor(n / 1000);
      const r = n % 1000;
      const kTxt = k === 1 ? 'mille' : `${under1000(k)} mille`;
      return r === 0 ? kTxt : `${kTxt} ${under1000(r)}`;
    }

    return String(n);
  }
}
